mapper.select:
SELECT id, username, password, nickname, phone, email, role, status, created_at, updated_at
FROM `user`
WHERE id = #{id}

SELECT id, username, password, nickname, phone, email, role, status, created_at, updated_at
FROM `user`
WHERE username = #{username}

mapper.update:
UPDATE `user`
nickname = #{nickname}, phone = #{phone}, email = #{email}, updated_at = NOW()
WHERE id = #{id}

UPDATE `user`
SET status = #{status}, updated_at = NOW()
WHERE id = #{id}
